import json
import time
import hashlib
import secrets
from datetime import datetime, timedelta
from typing import Optional, Dict, Any

from flask import Flask, request, jsonify
from flask_cors import CORS
from web3 import Web3
from eth_account.messages import encode_defunct
from functools import wraps

app = Flask(__name__)
CORS(app)
app.config['SECRET_KEY'] = secrets.token_hex(32)

# Initialize Web3
w3 = Web3()

# In-memory stores (replace with database in production)
nonce_store: Dict[str, Dict[str, Any]] = {}  # address -> {nonce, created_at}
session_store: Dict[str, Dict[str, Any]] = {}  # token -> {address, created_at, expires_at}
user_store: Dict[str, Dict[str, Any]] = {}  # address -> user profile

NONCE_EXPIRY_SECONDS = 300  # 5 minutes
SESSION_EXPIRY_SECONDS = 86400  # 24 hours
MESSAGE_TEMPLATE = "Sign this message to authenticate with our Web3 service.\n\nWallet: {address}\nNonce: {nonce}\nTimestamp: {timestamp}"


def generate_nonce() -> str:
    """Generate a cryptographically secure random nonce."""
    return secrets.token_hex(16)


def generate_session_token() -> str:
    """Generate a secure session token."""
    return secrets.token_hex(32)


def cleanup_expired_nonces():
    """Remove expired nonces from the store."""
    now = time.time()
    expired = [
        addr for addr, data in nonce_store.items()
        if now - data['created_at'] > NONCE_EXPIRY_SECONDS
    ]
    for addr in expired:
        del nonce_store[addr]


def cleanup_expired_sessions():
    """Remove expired sessions from the store."""
    now = time.time()
    expired = [
        token for token, data in session_store.items()
        if now > data['expires_at']
    ]
    for token in expired:
        del session_store[token]


def is_valid_ethereum_address(address: str) -> bool:
    """Validate an Ethereum address."""
    try:
        return Web3.is_address(address) and Web3.is_checksum_address(Web3.to_checksum_address(address))
    except Exception:
        return False


def recover_signer(message: str, signature: str) -> Optional[str]:
    """Recover the signer's address from a signed message."""
    try:
        message_encoded = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(
            message_encoded,
            signature=signature
        )
        return Web3.to_checksum_address(recovered_address)
    except Exception as e:
        print(f"Signature recovery failed: {e}")
        return None


def require_auth(f):
    """Decorator to require authentication for endpoints."""
    @wraps(f)
    def decorated(*args, **kwargs):
        cleanup_expired_sessions()

        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({
                'success': False,
                'error': 'Missing or invalid Authorization header'
            }), 401

        token = auth_header.split('Bearer ')[1]
        session = session_store.get(token)

        if not session:
            return jsonify({
                'success': False,
                'error': 'Invalid or expired session token'
            }), 401

        if time.time() > session['expires_at']:
            del session_store[token]
            return jsonify({
                'success': False,
                'error': 'Session expired'
            }), 401

        request.user_address = session['address']
        request.session_token = token
        return f(*args, **kwargs)

    return decorated


@app.route('/api/auth/nonce', methods=['POST'])
def request_nonce():
    """
    Step 1: Client requests a nonce for their wallet address.
    The nonce is used to create a unique message for signing.
    """
    cleanup_expired_nonces()

    data = request.get_json()
    if not data or 'address' not in data:
        return jsonify({
            'success': False,
            'error': 'Wallet address is required'
        }), 400

    address = data['address']

    try:
        address = Web3.to_checksum_address(address)
    except Exception:
        return jsonify({
            'success': False,
            'error': 'Invalid Ethereum address'
        }), 400

    if not is_valid_ethereum_address(address):
        return jsonify({
            'success': False,
            'error': 'Invalid Ethereum address format'
        }), 400

    nonce = generate_nonce()
    timestamp = datetime.utcnow().isoformat()

    message = MESSAGE_TEMPLATE.format(
        address=address,
        nonce=nonce,
        timestamp=timestamp
    )

    nonce_store[address] = {
        'nonce': nonce,
        'message': message,
        'timestamp': timestamp,
        'created_at': time.time()
    }

    return jsonify({
        'success': True,
        'data': {
            'message': message,
            'nonce': nonce,
            'expires_in': NONCE_EXPIRY_SECONDS
        }
    }), 200


@app.route('/api/auth/verify', methods=['POST'])
def verify_signature():
    """
    Step 2: Client submits the signed message.
    Server recovers the address and verifies it matches.
    """
    cleanup_expired_nonces()
    cleanup_expired_sessions()

    data = request.get_json()
    if not data:
        return jsonify({
            'success': False,
            'error': 'Request body is required'
        }), 400

    required_fields = ['address', 'signature']
    for field in required_fields:
        if field not in data:
            return jsonify({
                'success': False,
                'error': f'{field} is required'
            }), 400

    address = data['address']
    signature = data['signature']

    try:
        address = Web3.to_checksum_address(address)
    except Exception:
        return jsonify({
            'success': False,
            'error': 'Invalid Ethereum address'
        }), 400

    # Check if nonce exists for this address
    nonce_data = nonce_store.get(address)
    if not nonce_data:
        return jsonify({
            'success': False,
            'error': 'No authentication request found. Please request a nonce first.'
        }), 400

    # Check nonce expiry
    if time.time() - nonce_data['created_at'] > NONCE_EXPIRY_SECONDS:
        del nonce_store[address]
        return jsonify({
            'success': False,
            'error': 'Nonce has expired. Please request a new one.'
        }), 400

    # Recover the signer address from the signature
    message = nonce_data['message']
    recovered_address = recover_signer(message, signature)

    if not recovered_address:
        return jsonify({
            'success': False,
            'error': 'Failed to recover address from signature'
        }), 400

    # Verify the recovered address matches the claimed address
    if recovered_address.lower() != address.lower():
        # Consume the nonce to prevent replay
        del nonce_store[address]
        return jsonify({
            'success': False,
            'error': 'Signature verification failed. Recovered address does not match.'
        }), 401

    # Authentication successful - consume the nonce
    del nonce_store[address]

    # Create or update user profile
    if address not in user_store:
        user_store[address] = {
            'address': address,
            'created_at': datetime.utcnow().isoformat(),
            'last_login': datetime.utcnow().isoformat(),
            'login_count': 1
        }
    else:
        user_store[address]['last_login'] = datetime.utcnow().isoformat()
        user_store[address]['login_count'] = user_store[address].get('login_count', 0) + 1

    # Generate session token
    session_token = generate_session_token()
    expires_at = time.time() + SESSION_EXPIRY_SECONDS

    session_store[session_token] = {
        'address': address,
        'created_at': time.time(),
        'expires_at': expires_at
    }

    return jsonify({
        'success': True,
        'data': {
            'token': session_token,
            'address': address,
            'expires_in': SESSION_EXPIRY_SECONDS,
            'user': user_store[address]
        }
    }), 200


@app.route('/api/auth/session', methods=['GET'])
@require_auth
def get_session():
    """Get current session information."""
    session = session_store[request.session_token]
    user = user_store.get(request.user_address, {})

    return jsonify({
        'success': True,
        'data': {
            'address': request.user_address,
            'session_created': datetime.fromtimestamp(session['created_at']).isoformat(),
            'session_expires': datetime.fromtimestamp(session['expires_at']).isoformat(),
            'user': user
        }
    }), 200


@app.route('/api/auth/logout', methods=['POST'])
@require_auth
def logout():
    """Invalidate the current session."""
    del session_store[request.session_token]

    return jsonify({
        'success': True,
        'message': 'Successfully logged out'
    }), 200


@app.route('/api/auth/refresh', methods=['POST'])
@require_auth
def refresh_session():
    """Refresh the current session token."""
    old_session = session_store.pop(request.session_token)

    new_token = generate_session_token()
    expires_at = time.time() + SESSION_EXPIRY_SECONDS

    session_store[new_token] = {
        'address': old_session['address'],
        'created_at': time.time(),
        'expires_at': expires_at
    }

    return jsonify({
        'success': True,
        'data': {
            'token': new_token,
            'expires_in': SESSION_EXPIRY_SECONDS
        }
    }), 200


