@app.route('/api/auth/verify-address', methods=['POST'])
def verify_address_ownership():
    """
    One-shot verification: verify that a signature was produced by the claimed address.
    Does not create a session - useful for one-time verifications.
    """
    data = request.get_json()
    if not data:
        return jsonify({
            'success': False,
            'error': 'Request body is required'
        }), 400

    required_fields = ['address', 'message', 'signature']
    for field in required_fields:
        if field not in data:
            return jsonify({
                'success': False,
                'error': f'{field} is required'
            }), 400

    address = data['address']
    message = data['message']
    signature = data['signature']

    try:
        address = Web3.to_checksum_address(address)
    except Exception:
        return jsonify({
            'success': False,
            'error': 'Invalid Ethereum address'
        }), 400

    recovered_address = recover_signer(message, signature)

    if not recovered_address:
        return jsonify({
            'success': False,
            'error': 'Failed to recover address from signature'
        }), 400

    is_valid = recovered_address.lower() == address.lower()

    return jsonify({
        'success': True,
        'data': {
            'is_valid': is_valid,
            'claimed_address': address,
            'recovered_address': recovered_address
        }
    }), 200


