def demo_client_flow():
    """
    Demonstrates the authentication flow programmatically.
    This simulates what a frontend client would do.
    """
    from eth_account import Account

    print("=" * 60)
    print("Web3 Authentication Demo")
    print("=" * 60)

    # Generate a test account
    account = Account.create()
    print(f"\nTest wallet address: {account.address}")
    print(f"(Private key for demo only: {account.key.hex()})")

    # Step 1: Request nonce
    print("\n--- Step 1: Request Nonce ---")
    with app.test_client() as client:
        response = client.post('/api/auth/nonce', json={
            'address': account.address
        })
        nonce_response = response.get_json()
        print(f"Nonce response: {json.dumps(nonce_response, indent=2)}")

        message = nonce_response['data']['message']

        # Step 2: Sign the message
        print("\n--- Step 2: Sign Message ---")
        message_encoded = encode_defunct(text=message)
        signed_message = w3.eth.account.sign_message(
            message_encoded,
            private_key=account.key
        )
        signature = signed_message.signature.hex()
        print(f"Signature: {signature[:20]}...{signature[-20:]}")

        # Step 3: Verify signature
        print("\n--- Step 3: Verify Signature ---")
        response = client.post('/api/auth/verify', json={
            'address': account.address,
            'signature': signature
        })
        verify_response = response.get_json()
        print(f"Verify response: {json.dumps(verify_response, indent=2)}")

        if verify_response['success']:
            token = verify_response['data']['token']

            # Step 4: Access protected endpoint
            print("\n--- Step 4: Access Protected Endpoint ---")
            response = client.get('/api/protected/profile', headers={
                'Authorization': f'Bearer {token}'
            })
            profile_response = response.get_json()
            print(f"Profile response: {json.dumps(profile_response, indent=2)}")

            # Step 5: Update profile
            print("\n--- Step 5: Update Profile ---")
            response = client.put('/api/protected/profile',
                json={
                    'display_name': 'CryptoUser',
                    'bio': 'Web3 enthusiast'
                },
                headers={
                    'Authorization': f'Bearer {token}'
                }
            )
            update_response = response.get_json()
            print(f"Update response: {json.dumps(update_response, indent=2)}")

            # Step 6: Get session info
            print("\n--- Step 6: Session Info ---")
            response = client.get('/api/auth/session', headers={
                'Authorization': f'Bearer {token}'
            })
            session_response = response.get_json()
            print(f"Session response: {json.dumps(session_response, indent=2)}")

            # Step 7: Logout
            print("\n--- Step 7: Logout ---")
            response = client.post('/api/auth/logout', headers={
                'Authorization': f'Bearer {token}'
            })
            logout_response = response.get_json()
            print(f"Logout response: {json.dumps(logout_response, indent=2)}")

            # Verify session is invalidated
            print("\n--- Verify Session Invalidated ---")
            response = client.get('/api/protected/profile', headers={
                'Authorization': f'Bearer {token}'
            })
            invalid_response = response.get_json()
            print(f"After logout response: {json.dumps(invalid_response, indent=2)}")

    print("\n" + "=" * 60)
    print("Demo complete!")
    print("=" * 60)


